const raw = $env.MONITOR_SERVERS_JSON || '[]';
let servers;
try { servers = JSON.parse(raw); } catch (e) { servers = []; }
return servers.map(s => ({ json: s }));

// Build SSL summary across all servers. Alert if any domain <14d, otherwise silent.
const lines = [];
const critical = []; // <3d
const warning = [];  // 3..14d
const ok = [];       // >=14d

for (const item of $input.all()) {
  const data = item.json;
  const server = data.server || 'unknown';
  for (const d of (data.domains || [])) {
    if (!d.ok) {
      critical.push(<code>✗ ${d.host}:${d.port} — ${(d.error || 'check failed').slice(0, 80)}</code>);
      continue;
    }
    const days = d.days_left;
    const line = <code>${d.host}:${d.port} — ${days} kun (${d.expires_at.slice(0, 10)})</code>;
    if (days <= 3) critical.push(<code>🔴 ${line}</code>);
    else if (days <= 14) warning.push(<code>🟠 ${line}</code>);
    else ok.push(<code>🟢 ${line}</code>);
  }
}

if (!critical.length && !warning.length) {
  // Optionally send a daily 'all good' message — only if there are domains tracked
  if (!ok.length) return [];
  return [{ json: { message: <code>🔒 <b>SSL hisoboti</b>\n\nHammasi 14+ kun:\n</code> + ok.map(l => <code>• ${l}</code>).join('\n') } }];
}

let msg = '';
if (critical.length) msg += '🔴 <b>Kritik SSL</b> (<3 kun yoki xato)\n' + critical.map(l => <code>• ${l}</code>).join('\n') + '\n\n';
if (warning.length) msg += '🟠 <b>Diqqat</b> (<14 kun)\n' + warning.map(l => <code>• ${l}</code>).join('\n') + '\n\n';
if (ok.length) msg += <code>🟢 ${ok.length} ta domen 14+ kun\n</code>;

return [{ json: { message: msg.trim() } }];
